def dfs(u, p, disc, low, time, ap, graph):
    disc[u] = low[u] = time[0]
    time[0] += 1
    for v in graph[u]:
        if v == p: continue
        if disc[v] == -1:
            dfs(v, u, disc, low, time, ap, graph)
            low[u] = min(low[u], low[v])
            if p != -1 and low[v] >= disc[u]:
                    ap[u] = True
        else:
            low[u] = min(low[u], disc[v])
    return
